    uint32_t W_conv = W - kW + 1;
    uint32_t H_out = H_conv / K;
    uint32_t W_out = W_conv / K;
    uint32_t totalY = N * outC * H_out * W_out;

    // Simple tile sizing: process one output element per thread? UB budget: approximate
    uint32_t tileLen = 4096; // placeholder
    if (totalY < tileLen) tileLen = totalY;
    uint32_t numTiles = CeilDiv(totalY, tileLen);
    uint32_t blockDim = std::min(24u, numTiles);
