    tiling->N = N; tiling->C = C; tiling->H = H; tiling->W = W;
    tiling->outC = outC; tiling->inC = inC; tiling->kH = kH; tiling->kW = kW;
    tiling->H_conv = H_conv; tiling->W_conv = W_conv;
    tiling->K = K; tiling->sub1 = sub1; tiling->sub2 = sub2;
    tiling->tileLen = tileLen;
    tiling->blockDim = blockDim;

    tiling->SaveToBuffer(context->GetRawTilingData()->GetData(),
                         context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling->GetDataSize());
    size_t *ws = context->GetWorkspaceSizes(1);
    ws[0] = 0;
